const ghJson = $('GitHub 현재 파일 조회').item.json;
const currentCode = Buffer.from(ghJson.content.replace(/\n/g, ''), 'base64').toString('utf-8');

// 어느 웹훅으로 들어왔는지 판단
let instruction = '';
try {
  instruction = $('Webhook soulkit-feedback').item.json.body.message;
} catch(e) {
  try {
    const spec = $('Webhook Claude Code 수신').first().json;
    instruction = spec.instruction || spec.body?.instruction || '';
  } catch(e2) {
    instruction = 'Fix any issues found in the code';
  }
}

const wbJson = $('Webhook soulkit-feedback').item.json.body;
const repoFull = wbJson.repo || 'joo11s/soulkit';
const repoParts = repoFull.includes('/') ? repoFull.split('/') : ['joo11s', repoFull];
return [{
  json: {
    sha: ghJson.sha,
    currentCode: currentCode,
    owner: repoParts[0],
    repo: repoParts[1],
    body: {
      model: 'claude-sonnet-4-20250514',
      max_tokens: 2000,
      system: 'You are a code fixing assistant. Given a task/bug report and HTML code, identify the exact fix needed. Return ONLY a JSON object with three fields: "old_code" (the exact string to find and replace, keep it short and unique), "new_code" (the replacement string), "commit_message" (short Korean description). No markdown.',
      messages: [{
        role: 'user',
        content: 'Task: ' + instruction + '\n\nHTML code:\n' + currentCode.substring(0, 3000)
      }]
    }
  }
}];

const msg = ($input.first().json.message?.text || '').trim();
const chatId = $input.first().json.message?.chat?.id;
if (!msg || msg.toLowerCase() === 'skip') return [{ json: { skip: true, chatId } }];
let nums = [];
if (msg.toLowerCase() === 'all') { nums = ['all']; }
else { nums = msg.split(',').map(s=>parseInt(s.trim())).filter(n=>!isNaN(n)); }
return [{ json: { nums, chatId, skip: false } }];

const nums = $('승인 파싱').first().json.nums;
const tasks = $input.all().map(t=>t.json);
let filtered;
if (nums.includes('all')) { filtered = tasks.filter(t=>t.category!=='REJECT'); }
else { filtered = tasks.filter((_,i)=>nums.includes(i+1)); }
return filtered.map(t=>({ json: t }));

