const response = $input.first().json;
const rawRows = response.values || [];
if (rawRows.length === 0) {
  return [{ json: { agents: {}, rows: [], total: 0, ts: new Date().toISOString() } }];
}
const headers = rawRows[0]; // ['agent', 'status', 'message', 'updated_at']
const dataRows = rawRows.slice(1).map(row => {
  const obj = {};
  headers.forEach((h, i) => { obj[h] = row[i] || ''; });
  return obj;
});
const agents = {};
for (const row of dataRows) {
  if (row.agent) agents[row.agent] = row;
}
return [{ json: { agents, rows: dataRows, total: dataRows.length, ts: new Date().toISOString() } }];

const body = $('Webhook Claude Code 수신').first().json.body;
const instruction = body.instruction || body.task || '';
const n8nKey = $env.N8N_API_KEY;
const n8nBase = 'https://n8n.wonflowai.com/api/v1';
const anthropicKey = $env.ANTHROPIC_API_KEY;

const systemPrompt = 'n8n 워크플로우 전문가. n8n_api 툴로 n8n API를 직접 호출해서 작업 수행. base: ' + n8nBase + ', key: ' + n8nKey + '. 완료 후 ===RESULT_START=== 결과요약 ===RESULT_END=== 형식으로 반환.';

const tool = { name: 'n8n_api', description: 'n8n API 호출', input_schema: { type: 'object', properties: { method: {type:'string',enum:['GET','PUT']}, url: {type:'string'}, body: {type:'string'} }, required: ['method','url'] } };

let messages = [{ role: 'user', content: instruction }];
let response;

const callClaude = async (msgs) => {
  const r = await fetch('https://api.anthropic.com/v1/messages', {
    method: 'POST',
    headers: {'Content-Type':'application/json','x-api-key':anthropicKey,'anthropic-version':'2023-06-01'},
    body: JSON.stringify({ model:'claude-sonnet-4-20250514', max_tokens:16000, system:systemPrompt, messages:msgs, tools:[tool] })
  });
  return r.json();
};

response = await callClaude(messages);

let loopCount = 0;
while (response.stop_reason === 'tool_use' && loopCount < 10) {
  loopCount++;
  const toolUses = response.content.filter(c => c.type === 'tool_use');
  const toolResults = [];
  for (const tu of toolUses) {
    const { method, url, body: reqBody } = tu.input;
    const opts = { method, headers: {'X-N8N-API-KEY':n8nKey,'Content-Type':'application/json'} };
    if (reqBody) opts.body = reqBody;
    let toolResult;
    try { const ar = await fetch(url, opts); const ad = await ar.json(); toolResult = JSON.stringify(ad).slice(0,2000); }
    catch(e) { toolResult = 'Error: ' + e.message; }
    toolResults.push({ type:'tool_result', tool_use_id:tu.id, content:toolResult });
  }
  messages = [{ role:'user', content:instruction }, { role:'assistant', content:response.content }, { role:'user', content:toolResults }];
  response = await callClaude(messages);
}

const textBlocks = response.content?.filter(c=>c.type==='text').map(c=>c.text).join('') || '완료';
let result = textBlocks.includes('===RESULT_START===') ? textBlocks.split('===RESULT_START===')[1].split('===RESULT_END===')[0].trim() : textBlocks.slice(0,300);
return [{ json: { result } }];

const categories=$input.first().json.categories||[];
function buildTree(items,p){return items.filter(i=>Number(i.parent_category_no)===Number(p)).map(i=>{const n={no:Number(i.category_no),name:i.category_name,depth:Number(i.category_depth)};const c=buildTree(items,i.category_no);if(c.length>0)n.children=c;return n;});}
let tree=buildTree(categories,1);
if(tree.length===0)tree=buildTree(categories,0);
return [{json:{updated_at:new Date().toISOString(),mall_name:'행복산업',categories:tree}}];

const categories=$input.first().json.categories||[];
function buildTree(items,p){return items.filter(i=>Number(i.parent_category_no)===Number(p)).map(i=>{const n={no:Number(i.category_no),name:i.category_name,depth:Number(i.category_depth)};const c=buildTree(items,i.category_no);if(c.length>0)n.children=c;return n;});}
let tree=buildTree(categories,1);
if(tree.length===0)tree=buildTree(categories,0);
return [{json:{updated_at:new Date().toISOString(),mall_name:'제이원투몰',categories:tree}}];

const categories=$input.first().json.categories||[];
function buildTree(items,p){return items.filter(i=>Number(i.parent_category_no)===Number(p)).map(i=>{const n={no:Number(i.category_no),name:i.category_name,depth:Number(i.category_depth)};const c=buildTree(items,i.category_no);if(c.length>0)n.children=c;return n;});}
let tree=buildTree(categories,1);
if(tree.length===0)tree=buildTree(categories,0);
return [{json:{updated_at:new Date().toISOString(),mall_name:'소울스토어',categories:tree}}];

const body = $('Webhook Claude Code 수신').first().json.body;

// 필수값 검증
if (!body.repo) throw new Error('CC 오류: repo 파라미터가 없습니다. {type, repo, instruction} 필수');
if (!body.instruction) throw new Error('CC 오류: instruction 파라미터가 없습니다.');

const repo = body.repo;
const file = body.file || null;

// instruction 앞에 repo/file 컨텍스트 자동 주입
// → CC가 어떤 파일을 건드려야 하는지 항상 명확하게 전달
let context = '=== 작업 대상 ===\n';
context += 'GitHub repo: ' + repo + '\n';
if (file) {
  context += '수정할 파일: ' + file + '\n';
} else {
  context += '수정할 파일: repo 내 관련 파일을 스스로 판단\n';
}
context += '=== 작업 지시 ===\n';

const fullInstruction = context + body.instruction;

// base64 인코딩
const b64 = Buffer.from(fullInstruction).toString('base64');

return [{ json: { repo, file, instruction_b64: b64 } }];

const mall_id = $json.query.mall_id;

const clientMap = {
  'godqhrtksdjq': '3aIdaLfPS6EDpTb5fRWnQF',
  'jonetravel':   'oIZhc3pNChskFydn2IIydD',
  'soulstore3':   'eAOW31eJdEfhl1dtPp753e'
};

const client_id = clientMap[mall_id] || '3aIdaLfPS6EDpTb5fRWnQF';
const redirect_uri = encodeURIComponent('https://n8n.wonflowai.com/webhook/cafe24-oauth');
const scope = 'mall.read_application,mall.write_application,mall.read_category,mall.write_category,mall.read_product,mall.write_product,mall.read_order,mall.write_order';
const state = mall_id + '_' + Date.now();

const authUrl = `https://${mall_id}.cafe24api.com/api/v2/oauth/authorize?response_type=code&client_id=${client_id}&state=${state}&redirect_uri=${redirect_uri}&scope=${scope}`;

return [{ json: { authUrl, mall_id, client_id } }];

// ⚠️ 아래 clientSecret 값을 직접 입력하세요 (한 번만)
const secretMap = {
  'soulstore3':   { clientId: 'eAOW31eJdEfhl1dtPp753e', clientSecret: 'AU2Mf4b3SyqSn5jvdLJrgE' },
  'jonetravel':   { clientId: 'oIZhc3pNChskFydn2IIydD', clientSecret: 'oq3Cbfn7ZKcdXY7fcPfDfj' },
  'godqhrtksdjq': { clientId: '3aIdaLfPS6EDpTb5fRWnQF', clientSecret: 'Nz7JFbWXKJAvnUsZdplAcA' }
};

// state 파라미터에서 mall_id 추출 (state = "mall_id_timestamp" 형식)
const state = $json.query.state || '';
const code = $json.query.code || '';
const mall_id = state.split('_')[0];

const cfg = secretMap[mall_id];
if (!cfg) {
  throw new Error('mall_id 매핑 실패: ' + mall_id + ' / state: ' + state);
}

const basicAuth = 'Basic ' + Buffer.from(cfg.clientId + ':' + cfg.clientSecret).toString('base64');

return [{ json: { mall_id, code, basicAuth } }];

const raw = $input.first().json;
let body;
if (Array.isArray(raw.body)) {
  body = raw.body[0].body;
} else {
  body = raw.body || raw;
}

const product = body.product || {};
const stores = body.stores || {};
const commonImages = body.commonImages || {};

const descHtml = (commonImages.detail || []).map(url => `<img src='${url}' style='width:100%'>`).join('');

const makeStore = (storeKey) => {
  const s = stores[storeKey] || {};
  return {
    product_name:    s.productName || product.name || '',
    price:           Number(product.salePrice) || 0,
    supply_price:    Number(product.supplyPrice) || 0,
    consumer_price:  Number(product.consumerPrice) || 0,
    display:         product.displayStatus || 'T',
    selling:         product.saleStatus || 'T',
    category_no:     parseInt(product.categoryNo) || 53,
    tax_calculation: product.taxType || 'A',
    description:     descHtml,
    summary_description: s.productName || product.name || '',
    main_image: (s.images && s.images.main && s.images.main[0]) || '',
    has_options: !!(s.options && s.options.length),
    options: s.options || []
  };
};

return [{ json: {
  product_name: (stores.soul || {}).productName || product.name || '',
  soul:  makeStore('soul'),
  j12:   makeStore('j12'),
  happy: makeStore('happy')
}}];

