// fullTree 파싱 및 depth별 그룹화
const resp = $input.first().json;
const fullTree = (resp.fullTree || []).filter(c => c.path && c.path.split('>')[0].trim() === '식품');
const byDepth = { 1: [], 2: [], 3: [], 4: [] };
for (const cat of fullTree) {
    const d = cat.path.split('>').length;  if (d >= 1 && d <= 4) byDepth[d].push(cat);
}

return [{
  json: {
    fullTree,
    byDepth,
    totalCount: fullTree.length,
    depth1Count: byDepth[1].length,
    depth2Count: byDepth[2].length,
    depth3Count: byDepth[3].length,
    depth4Count: byDepth[4].length,
  }
}];

// 소울스토어 - 표준카테고리 depth 1→4 순차 생성
const item = $input.first().json;
const fullTree = item.fullTree;

// OAuth2 액세스 토큰 획득
let accessToken;
try {
  const creds = await this.getCredentials('oAuth2Api');
  accessToken = creds.access_token || creds.accessToken;
  if (!accessToken) throw new Error('access_token 필드 없음');
} catch(e) {
  throw new Error('OAuth2 크레덴셜 오류: ' + e.message);
}

const baseUrl = 'https://soulstore3.cafe24api.com';
const codeToNo = {};
const stats = { shop: '소울스토어', created: 0, failed: 0, skipped: 0, errors: [] };

// depth 1 → 2 → 3 → 4 순서로 처리
for (let depth = 1; depth <= 4; depth++) {
  const depthCats = fullTree.filter(c => c.path.split('>').length === depth);  
  for (const cat of depthCats) {
    let parentCategoryNo = 1;
    if (depth > 1) {
      if (!cat.parent || codeToNo[cat.parent] === undefined) {
        stats.skipped++;
        continue;
      }
      parentCategoryNo = codeToNo[cat.parent];
    }

    try {
      const resp = await this.helpers.httpRequest({
        method: 'POST',
        url: `${baseUrl}/api/v2/admin/categories`,
        headers: {
          Authorization: `Bearer ${accessToken}`,
          'X-Cafe24-Api-Version': '2026-03-01',
          'Content-Type': 'application/json',
        },
        json: true,
        body: {
          request: {
            category_name: cat.name,
            parent_category_no: parentCategoryNo,
            category_depth: depth,
            display: 'T',
          },
        },
        ignoreHttpStatusErrors: true,
      });

      if (resp && resp.category && resp.category.category_no) {
        codeToNo[cat.code] = resp.category.category_no;
        stats.created++;
      } else if (resp && resp.errors) {
        // 이미 존재하거나 다른 오류
        stats.failed++;
        if (stats.errors.length < 10) stats.errors.push({ code: cat.code, err: JSON.stringify(resp.errors) });
      } else {
        stats.failed++;
      }
    } catch (err) {
      stats.failed++;
      if (stats.errors.length < 10) stats.errors.push({ code: cat.code, err: err.message });
    }

    // 레이트 리밋 방지
    await new Promise(r => setTimeout(r, 100));
  }
}

return [{ json: { ...stats, mappingCount: Object.keys(codeToNo).length, fullTree } }];

